challenges.solution:
uniform vec2 u_resolution;
uniform sampler2D u_texture0;
out vec4 fragColor;

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;
    vec2 texel = 1.0 / u_resolution;

    vec4 col = vec4(0.0);
    for (int x = -1; x <= 1; x++) {
        for (int y = -1; y <= 1; y++) {
            col += texture(u_texture0, uv + vec2(float(x), float(y)) * texel * 3.0);
        }
    }
    col /= 9.0;

    fragColor = col;
}

hlsl.code:
cbuffer Uniforms : register(b0) {
    float2 u_resolution;
};

Texture2D u_texture0 : register(t0);
SamplerState u_sampler : register(s0);

float4 main(float4 pos : SV_Position) : SV_Target {
    float2 uv = pos.xy / u_resolution;
    float2 texel = 1.0 / u_resolution;

    float4 col = float4(0.0, 0.0, 0.0, 0.0);
    for (int x = -1; x <= 1; x++) {
        for (int y = -1; y <= 1; y++) {
            col += u_texture0.Sample(u_sampler, uv + float2((float)x, (float)y) * texel * 3.0);
        }
    }
    return col / 9.0;
}

